"""matplotlib.dviread — DVI file reading stubs."""

class Dvi:
    def __init__(self, filename, dpi): pass
    def __iter__(self): return iter([])
    def close(self): pass
    def __enter__(self): return self
    def __exit__(self, *args): self.close()

class DviFont:
    def __init__(self, scale, tfm, texname, vf): pass

class Tfm:
    def __init__(self, filename): pass

class Vf(Dvi):
    pass

class PsFont:
    def __init__(self, texname, psname, effects): pass

class PsfontsMap:
    def __init__(self, filename): pass
    def __getitem__(self, texname): return None
